// Created: 2026-06-12

/**
 * Session Identity (core) — Haiku-powered auto-rename + auto-color for CC
 * sessions. Pure helpers: palette, fallback color, generator prompt/spawn,
 * output parsing, title merge. Orchestration lives in
 * session-identity-state.ts (driven by prompt/unified-dispatcher).
 *
 * Delivery channels (verified against the CC 2.1.175 binary):
 * - TITLE: `hookSpecificOutput.sessionTitle` (UserPromptSubmit, CC 2.1.94+)
 *   updates the live prompt bar — fully supported hook surface.
 * - COLOR: no hook surface exists. `/color` persists by appending
 *   `{"type":"agent-color","agentColor":"<c>","sessionId":"<id>"}` to the
 *   session transcript jsonl; the session list / resume picker rebuilds from
 *   the LAST such record. We append the same shape. Limitation: the live
 *   prompt bar only shows it after resume — CC's in-memory accent color has
 *   no external setter.
 */

import { openSync } from 'node:fs';
import { spawn } from 'node:child_process';
import type { HookContext } from '../types.js';

/** Named palette accepted by `/color` (CC 2.1.128) — no hex values. */
export const SESSION_COLOR_PALETTE = [
  'red',
  'blue',
  'green',
  'yellow',
  'purple',
  'orange',
  'pink',
  'cyan',
] as const;

export type SessionColor = (typeof SESSION_COLOR_PALETTE)[number];

export interface SessionIdentity {
  title: string;
  color: SessionColor;
}

/** Recursion guard env marker for the child `claude -p` call. */
export const CHILD_ENV_MARKER = 'ORK_SESSION_IDENTITY_CHILD';

/** Max chars of the AI title kept in the merged prompt-bar title. */
export const AI_TITLE_MAX = 38;

/** First-prompt excerpt length passed to haiku. */
const PROMPT_EXCERPT_MAX = 600;

/**
 * Stable palette pick from the session id (FNV-1a). Two concurrent sessions
 * usually differ visually even before (or without) the haiku result.
 */
export function hashColor(sessionId: string): SessionColor {
  let hash = 0x811c9dc5;
  for (let i = 0; i < sessionId.length; i++) {
    hash ^= sessionId.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return SESSION_COLOR_PALETTE[(hash >>> 0) % SESSION_COLOR_PALETTE.length];
}

export function buildGeneratorPrompt(firstPrompt: string, branch: string): string {
  const excerpt = firstPrompt.replace(/\s+/g, ' ').trim().slice(0, PROMPT_EXCERPT_MAX);
  return [
    'You name coding sessions. Given the first user prompt of a session, output STRICT JSON only — no prose, no code fences:',
    `{"title":"<3-6 word topic title>","color":"<one of: ${SESSION_COLOR_PALETTE.join(', ')}>"}`,
    'Pick the color that best matches the work (red=bugfix/incident, green=feature, blue=docs/research, yellow=refactor, purple=infra/CI, orange=perf, pink=design/UX, cyan=testing).',
    branch ? `Git branch: ${branch}` : '',
    `First prompt: ${excerpt}`,
  ]
    .filter(Boolean)
    .join('\n');
}

/**
 * Spawn a detached `claude -p` (haiku) that writes its stdout to rawOutPath.
 * Fire-and-forget: never blocks the hook, never throws.
 *
 * - `--settings '{"disableAllHooks":true}'` keeps the child cheap and stops
 *   this hook from running inside it (recursion guard #1).
 * - CHILD_ENV_MARKER is recursion guard #2 in case settings are ignored.
 * - Plain `claude -p` (NOT --bare — broken auth) so subscription auth works;
 *   no API key required.
 */
export function spawnIdentityGenerator(
  firstPrompt: string,
  branch: string,
  rawOutPath: string,
  ctx?: HookContext,
): boolean {
  try {
    const outFd = openSync(rawOutPath, 'w');
    const child = spawn(
      'claude',
      [
        '-p',
        '--model',
        'haiku',
        '--settings',
        '{"disableAllHooks":true}',
        buildGeneratorPrompt(firstPrompt, branch),
      ],
      {
        detached: true,
        stdio: ['ignore', outFd, 'ignore'],
        env: { ...process.env, [CHILD_ENV_MARKER]: '1' },
      },
    );
    child.on('error', () => {
      /* ENOENT etc. — fail open, raw file stays empty and goes stale */
    });
    child.unref();
    return true;
  } catch (error) {
    ctx?.log?.('session-identity', `generator spawn failed: ${error}`, 'warn');
    return false;
  }
}

/**
 * Parse the generator's stdout. Tolerates fences/prose around the JSON by
 * extracting the outermost {...} block. Returns null unless both fields
 * validate (title ≥ 3 chars, color in palette).
 */
export function parseIdentityOutput(raw: string): SessionIdentity | null {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start < 0 || end <= start) return null;
  try {
    const parsed: unknown = JSON.parse(raw.slice(start, end + 1));
    if (typeof parsed !== 'object' || parsed === null) return null;
    const obj = parsed as Record<string, unknown>;
    const title = typeof obj.title === 'string' ? obj.title.replace(/\s+/g, ' ').trim() : '';
    const color = typeof obj.color === 'string' ? obj.color.toLowerCase().trim() : '';
    if (!title || title.length < 3) return null;
    if (!(SESSION_COLOR_PALETTE as readonly string[]).includes(color)) return null;
    return { title: title.slice(0, AI_TITLE_MAX), color: color as SessionColor };
  } catch {
    return null;
  }
}

/**
 * Merge the AI title with the branch-derived title for the 60-char prompt
 * bar. AI topic first (what), branch second (where).
 */
export function mergeIdentityTitle(aiTitle: string, branchTitle: string): string {
  const ai = aiTitle.slice(0, AI_TITLE_MAX);
  if (!branchTitle) return ai.slice(0, 60);
  return `${ai} · ${branchTitle}`.slice(0, 60);
}
